@Composable
fun Carousel(
    modifier: Modifier = Modifier,
    movieCards: List<MovieCard>
) {
    val pagerState = rememberPagerState(2) { movieCards.size }
    HorizontalPager(
        modifier = modifier,
        beyondViewportPageCount = movieCards.size,
        pageSpacing = (-50).dp,
        contentPadding = PaddingValues(horizontal = 24.dp),
        state = pagerState,
    ) { pageIndex ->
        val isSelected = pageIndex == pagerState.currentPage
        val zIndex = animateFloatAsState(
            targetValue = if (isSelected) 1f else 0f,
            label = "ZIndexAnimation"
        ).value
        MovieItem(
            modifier = Modifier.zIndex(zIndex),
            movieCard = movieCards[pageIndex],
            isSelected = isSelected
        )
    }
}

@Composable
private fun MovieItem(
    modifier: Modifier = Modifier,
    movieCard: MovieCard,
    isSelected: Boolean
) {
    val width = animateDpAsState(
        targetValue = if (!isSelected) 312.dp else 360.dp,
        label = "ImageWidthAnimation"
    ).value
    Column(
        modifier = modifier.fillMaxWidth(),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        Cover(
            modifier = Modifier.width(width),
            imageUrl = movieCard.coverUrl,
            rate = movieCard.rate,
            isSelected = isSelected
        )
        if (isSelected) {
            Column(
                modifier = Modifier
                    .padding(horizontal = 12.dp)
                    .padding(bottom = 7.dp),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                Text(
                    modifier = Modifier.fillMaxWidth(),
                    text = movieCard.title,
                    style = Theme.textStyle.body.md.medium,
                    color = Theme.color.shade.primary,
                    textAlign = TextAlign.Center,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis
                )
                Text(
                    modifier = Modifier.fillMaxWidth(),
                    text = movieCard.tags.joinToString(separator = ", "),
                    style = Theme.textStyle.body.sm.regular,
                    color = Theme.color.shade.secondary,
                    textAlign = TextAlign.Center,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis
                )
            }
        }
    }
}

@Composable
private fun Cover(
    modifier: Modifier = Modifier,
    imageUrl: String,
    rate: Double,
    isSelected: Boolean
) {
    Box {
        SafeIslamicImage(
            modifier = modifier
                .aspectRatio(312 / 200f)
                .clip(RoundedCornerShape(Theme.radius.xl))
                .shadow(
                    80.dp,
                    RoundedCornerShape(Theme.radius.xl),
                    ambientColor = Color.Black.copy(.4f)
                ),
            imageUrl = imageUrl,
            contentDescription = "cover",
            contentScale = ContentScale.Crop
        )
        AnimatedVisibility(
            modifier = Modifier.align(Alignment.TopEnd),
            visible = isSelected,
            enter = fadeIn(),
            exit = fadeOut()
        ) {
            Row(
                modifier = Modifier
                    .padding(12.dp)
                    .background(
                        color = Theme.color.background.card,
                        shape = RoundedCornerShape(Theme.radius.full),
                    )
                    .padding(vertical = 4.dp)
                    .padding(start = 8.dp, end = 6.dp),
                horizontalArrangement = Arrangement.spacedBy(4.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = rate.toString(),
                    style = Theme.textStyle.label.md.medium,
                    color = Theme.color.shade.primary
                )
                Icon(
                    modifier = Modifier.size(16.dp),
                    painter = painterResource(Theme.icons.dueTone.star),
                    tint = Theme.color.additional.primary.yellow,
                    contentDescription = "star rate"
                )
            }
        }
    }

}

